"""
offlinai_intellisense — editor autocomplete docstring/signature daemon.

CodeBench's IntelliSenseEngine.swift resolves completion items over a
signal-file channel: it writes
    <tmp>/intellisense_signals/req_<id>.json   = {"id", "qualifier", "name"}
and polls (3 s) for
    <tmp>/intellisense_signals/resp_<id>.json  = {"documentation", "signature"}

GameViewController launches this daemon at startup with
    from offlinai_intellisense import start; start()
on a background thread. `start()` returns immediately after spawning a
Python daemon thread that answers requests by introspecting
`qualifier.name` with the `inspect` module.

This module previously did not exist, so the import failed
(ModuleNotFoundError) and editor autocomplete never showed docstrings
or signatures (every lookup timed out after 3 s).
"""

import glob
import importlib
import inspect
import json
import os
import tempfile
import threading
import time

_SIGNAL_DIR = os.path.join(tempfile.gettempdir(), "intellisense_signals")
_DOC_MAX = 4000          # cap docstring length sent back to the editor
_POLL_SECONDS = 0.05     # 50 ms — matches the Swift poll cadence
_started = False
_lock = threading.Lock()


def _resolve(qualifier, name):
    """Return (documentation, signature) for the symbol `qualifier.name`.

    Tries, in order: attribute of an imported module, a submodule, then a
    bare builtin/global. Never raises — returns ("", "") on any miss.
    """
    obj = None

    # 1. qualifier is a module, name is an attribute (numpy.array, os.getcwd)
    if qualifier:
        try:
            mod = importlib.import_module(qualifier)
            obj = getattr(mod, name, None)
        except Exception:
            obj = None

    # 2. qualifier.name is itself a module (os.path, numpy.linalg)
    if obj is None and qualifier:
        try:
            obj = importlib.import_module(qualifier + "." + name)
        except Exception:
            obj = None

    # 3. no qualifier — a builtin or keyword (print, len, range)
    if obj is None and not qualifier:
        try:
            obj = getattr(__builtins__, name, None) if hasattr(__builtins__, name) \
                else __builtins__.get(name) if isinstance(__builtins__, dict) else None
        except Exception:
            obj = None

    if obj is None:
        return "", ""

    # docstring
    try:
        doc = inspect.getdoc(obj) or ""
    except Exception:
        doc = ""
    if len(doc) > _DOC_MAX:
        doc = doc[:_DOC_MAX] + "\n…"

    # signature (callables only)
    sig = ""
    try:
        sig = name + str(inspect.signature(obj))
    except (TypeError, ValueError):
        # builtins/C-extensions often have no introspectable signature;
        # fall back to the first line of the docstring if it looks like one.
        if doc:
            first = doc.split("\n", 1)[0].strip()
            if name + "(" in first:
                sig = first
    except Exception:
        sig = ""

    return doc, sig


def _classify(obj):
    """Map a Python object to a CompletionKind raw value (LSP spec).

    Must match Swift's `CompletionKind` and `PythonSymbolIndex.build()`
    so the editor assigns the right icon/color to each member.
    """
    try:
        if inspect.ismodule(obj):
            return 9                                      # module
        if inspect.isclass(obj):
            return 7                                      # class
        if inspect.ismethod(obj):
            return 2                                      # method
        if inspect.isfunction(obj) or inspect.isbuiltin(obj):
            return 3                                      # function
        if isinstance(obj, type):
            return 7                                      # class
        if isinstance(obj, (int, float, complex, bool, bytes)):
            return 21                                     # constant
        if isinstance(obj, str):
            return 21                                     # constant (string)
        if isinstance(obj, (list, tuple, set, frozenset, dict)):
            return 6                                      # collection
        if callable(obj):
            return 3                                      # function fallback
        return 6                                          # variable
    except Exception:
        return 6


def _members(module):
    """Return {public_name: kind} for `module` via dir().

    Imports `module` if needed (importlib caches it after the first
    call), so the first `module.` completion for a heavy package may take
    a beat. Returns {} on any failure — the editor then simply shows
    nothing rather than hanging. Capped at 500 members.
    """
    if not module:
        return {}
    try:
        mod = importlib.import_module(module)
    except Exception:
        return {}
    try:
        names = dir(mod)
    except Exception:
        return {}
    out = {}
    count = 0
    for name in names:
        if name.startswith("_"):
            continue
        if count >= 500:
            break
        try:
            out[name] = _classify(getattr(mod, name))
        except Exception:
            out[name] = 6
        count += 1
    return out


def _handle(req_path):
    """Process one req_*.json → write resp_*.json, remove the request."""
    try:
        with open(req_path, "r", encoding="utf-8") as f:
            req = json.load(f)
    except Exception:
        # malformed / half-written request — drop it
        try:
            os.unlink(req_path)
        except OSError:
            pass
        return

    rid = req.get("id")
    if not rid:
        try:
            os.unlink(req_path)
        except OSError:
            pass
        return

    if req.get("op") == "members":
        # Lazy module-member introspection for editor autocomplete.
        resp = {"members": _members(req.get("module") or "")}
    else:
        doc, sig = _resolve(req.get("qualifier") or "", req.get("name") or "")
        resp = {"documentation": doc, "signature": sig}

    resp_path = os.path.join(_SIGNAL_DIR, "resp_%s.json" % rid)
    tmp_path = resp_path + ".tmp"
    try:
        with open(tmp_path, "w", encoding="utf-8") as f:
            json.dump(resp, f)
        os.replace(tmp_path, resp_path)   # atomic — Swift never sees a partial file
    except Exception:
        try:
            os.unlink(tmp_path)
        except OSError:
            pass
    finally:
        try:
            os.unlink(req_path)
        except OSError:
            pass


def _loop():
    while True:
        try:
            os.makedirs(_SIGNAL_DIR, exist_ok=True)
            for req_path in glob.glob(os.path.join(_SIGNAL_DIR, "req_*.json")):
                _handle(req_path)
        except Exception:
            pass  # never let the daemon thread die
        time.sleep(_POLL_SECONDS)


def start():
    """Spawn the IntelliSense daemon thread (idempotent). Returns at once."""
    global _started
    with _lock:
        if _started:
            return
        _started = True
    os.makedirs(_SIGNAL_DIR, exist_ok=True)
    t = threading.Thread(target=_loop, name="offlinai-intellisense", daemon=True)
    t.start()
